<?php
 namespace WPAICG\AutoGPT\Cron\EventProcessor\Trigger\Modules; if (!defined('ABSPATH')) { exit; } function manual_mode_generate_items_logic(array $task_config): array { $raw = $task_config['content_title'] ?? ''; if ($raw === '') { return []; } $lines = preg_split('/\r?\n/', $raw); $items = []; foreach ($lines as $line) { $line = trim($line); if ($line === '') { continue; } if (strpos($line, '|') === false) { $items[] = $line; continue; } $parts = array_map('trim', explode('|', $line)); $topic = $parts[0] ?? ''; if ($topic === '') { continue; } $item = [ 'topic' => $topic, ]; if (isset($parts[1]) && $parts[1] !== '') { $item['keywords'] = $parts[1]; } if (isset($parts[2]) && is_numeric($parts[2])) { $item['category'] = $parts[2]; } if (isset($parts[3]) && $parts[3] !== '') { $item['author'] = $parts[3]; } if (isset($parts[4]) && $parts[4] !== '') { $item['post_type'] = $parts[4]; } if (isset($parts[5]) && $parts[5] !== '') { $item['schedule_date'] = $parts[5]; } $items[] = $item; } return $items; } 